const body = $json.body ?? $json;
let rawMessage = String(body.message ?? body.text ?? body.query ?? '').trim();
let message = rawMessage;
const context = body.context ?? {};

if (!message) {
  return [{
    json: {
      ok: false,
      error: 'Message is required.',
      reply: 'Please type a question so I can help with the dashboard or agent workflow.',
      suggestions: ['Show sales by product type', 'Summarize branch stock', 'Top products by stock']
    }
  }];
}

const isShort = message.split(/\s+/).length <= 3 || /^(show|show me|yes|ok|sure|do it)$/i.test(message);
let intent = 'general';
let reply = 'I can help with sales, stock, dashboard context, or routing a task to the Openclaw agent workflow.';
let dashboard = 'Sales demo';
let actionHint = 'Ask for a chart, a summary, or a branch/product breakdown.';
let suggestions = [
  'Show sales by product type',
  'Show branch stock by city',
  'Top 5 products by stock'
];

function applyIntentValues(key) {
  switch(key) {
    case 'sales_trend':
      intent = 'sales_trend';
      reply = 'Pull the Sales Trend chart and compare the current week with the previous week.';
      dashboard = 'Sales Trend';
      actionHint = 'Use the daily trend question in Metabase to show movement over time.';
      suggestions = ['Daily sales trend', 'Weekly sales delta', 'Monthly comparison'];
      break;
    case 'product_mix':
      intent = 'product_mix';
      reply = 'I can summarize how sales are split across product types and highlight the leading category.';
      dashboard = 'Product Mix';
      actionHint = 'Use the product type question and a bar chart for quick comparison.';
      suggestions = ['Top product types', 'Compare categories', 'Show product mix'];
      break;
    case 'branch_stock':
      intent = 'branch_stock';
      reply = 'I can show branch stock by city and surface the branches with the highest inventory.';
      dashboard = 'Branch Stock';
      actionHint = 'Use the branch city aggregation to compare inventory across locations.';
      suggestions = ['Stock by city', 'Top branches by stock', 'Low stock branches'];
      break;
    case 'top_products':
      intent = 'top_products';
      reply = 'I can list the highest-stock products and keep the image thumbnails visible for the client.';
      dashboard = 'Top Products';
      actionHint = 'Use the top products table with total stock and image URL.';
      suggestions = ['Top 5 products', 'Top 10 products', 'Show image table'];
      break;
    case 'dashboard_help':
      intent = 'dashboard_help';
      reply = 'The dashboard embed is ready. I can help route a request or explain which Metabase card to open.';
      dashboard = 'Metabase Embed';
      actionHint = 'Use the embedded dashboard and the sidebar for follow-up questions.';
      suggestions = ['Open the dashboard', 'Explain the cards', 'How embedding works'];
      break;
    default:
      intent = 'general';
      reply = 'I can help with sales, stock, dashboard context, or routing a task to the Openclaw agent workflow.';
      dashboard = 'Sales demo';
      actionHint = 'Ask for a chart, a summary, or a branch/product breakdown.';
      suggestions = ['Show sales by product type', 'Show branch stock by city', 'Top 5 products by stock'];
  }
}

if (context.followUp && context.previousIntent && isShort) {
  applyIntentValues(context.previousIntent);
} else {
  const normalized = message.toLowerCase();
  if (/trend|daily|weekly|revenue|sales over time/.test(normalized)) {
    applyIntentValues('sales_trend');
  } else if (/product type|product mix|category/.test(normalized)) {
    applyIntentValues('product_mix');
  } else if (/top product|top 5|top 10|most stocked|most stock/.test(normalized)) {
    applyIntentValues('top_products');
  } else if (/branch|city|stock/.test(normalized)) {
    applyIntentValues('branch_stock');
  } else if (/embed|dashboard|metabase/.test(normalized)) {
    applyIntentValues('dashboard_help');
  }
}

return [{
  json: {
    ok: true,
    intent,
    message,
    context,
    dashboard,
    reply,
    suggestions,
    actionHint,
    project: 'C-M'
  }
}];
